# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class Player : MonoBehaviour
{
    // Player stats
    public int health = 100;
    public int currency = 0;
    public float goldPerSecond = 1f;
    public float damageMultiplier = 1f;
    public int maxHealth = 100;

    // Shop items and prices
    public enum ItemType { Sword, Shield }
    public struct ItemPrice
    {
        public float price;
        public float discount;
    }

    public static readonly Dictionary<ItemType, ItemPrice> shopItems =
        new Dictionary<ItemType, ItemPrice>()
        {
            {ItemType.Sword, new ItemPrice() {price = 10f, discount = 0.5f}},
            {ItemType.Shield, new ItemPrice() {price = 20f, discount = 0.2f}}
        };

    // Shop function
    public bool BuyItem(ItemType itemType)
    {
        if (currency >= shopItems[itemType].price * (1 - shopItems[itemType].discount))
        {
            currency -= shopItems[itemType].price * (1 - shopItems[itemType].discount);
            ApplyEffect(itemType);
            return true;
        }
        else
            return false;
    }

    // Apply effect function
    private void ApplyEffect(ItemType itemType)
    {
        switch (itemType)
        {
            case ItemType.Sword:
                damageMultiplier += 0.5f;
                break;
            case ItemType.Shield:
                health += 10;
                maxHealth = Mathf.Max(maxHealth, health);
                break;
        }
    }

    // Damage function
    public void TakeDamage(float amount)
    {
        health -= (int)(amount * damageMultiplier);
        if (health < 0) health = 0;

        // Update UI with player stats
        Debug.Log($"Player Health: {health}, Currency: {currency}");
    }

    private void Update()
    {
        currency += goldPerSecond * Time.deltaTime;
    }
}